SELECT count(*) as count
FROM XBOLTDLM.CC_USER_STS 
WHERE MemberID = #{MemberID}

SELECT TTX2.Name CompanyNM, XBOLTADM.fn_GetMyAbsPathForOrg(TT.TeamID,${languageID}) + '/' + NM_DEPT AS NM_DEPT, TTX3.Name VernderNM, ISNULL(YN_MANAGER,'-') AS YN_MANAGER, IDI.DEPT_FLAG, IDI.CD_DEPT, IDI.ID_USER FROM [XBOLTDLM].[ITUSER_DEPT_INFO] IDI
LEFT OUTER JOIN XBOLTADM.TB_TEAM TT ON TT.TeamCode = IDI.CD_DEPT AND TT.Deleted = 0 LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TTX ON TTX.TeamID = TT.TeamID AND TTX.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_TEAM TT2 ON TT2.RefTeamCode = IDI.CORP_ID and TT2.TeamType = 2 LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TTX2 ON TTX2.TeamID = TT2.TeamID AND TTX2.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_TEAM TT3 ON TT3.TeamCode = IDI.BIZ_KEY and TT3.TeamType = 54 LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TTX3 ON TTX3.TeamID = TT3.TeamID AND TTX3.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TM.LoginID = IDI.ID_USER WHERE TM.MemberID = ${memberID}

