SELECT TAB.CORP_ID ,MAX(TAB.CORP_NAME) DS_DEPT ,TAB.svc_ci_id1 ,TAB.svc_ci_id2 ,MAX(TAB.svc_ci_name1) svc_ci_name1 ,MAX(TAB.svc_ci_name) svc_ci_name , TAB.REQ_companycode ,MAX(TAB.REQ_companyNAME) REQ_companyNAME ,MAX(TAB.RequestTeamID) AS RequestTeamID ,SUM(TAB.DS_REQ1)+SUM(TAB.DS_REQ2)+SUM(TAB.DS_REQ3)+SUM(TAB.DS_APP) +SUM(TAB.DS_DATA)+SUM(TAB.DS_INFRA)+SUM(TAB.DS_SCM)+SUM(TAB.DS_INC)+SUM(TAB.DS_WORK) AS TOT ,SUM(TAB.DS_REQ1) DS_REQ1 , SUM(TAB.DS_REQ2) DS_REQ2 , SUM(TAB.DS_REQ3) DS_REQ3 , SUM(TAB.DS_APP) DS_APP , SUM(TAB.DS_DATA) DS_DATA ,SUM(TAB.DS_INFRA) DS_INFRA ,SUM(TAB.DS_SCM) DS_SECURITY ,SUM(TAB.DS_INC) DS_INC ,SUM(TAB.DS_WORK) DS_WORK ,SUM(TAB.CNTCOMPLETE) CNTCOMPLETE ,SUM(TAB.CNTCOMPLETE_DUE) CNTCOMPLETE_DUE ,SUM(TAB.FIRST_RCPT) FIRST_RCPT ,SUM(TAB.FIRST_SOLVE) FIRST_SOLVE ,(CASE WHEN SUM(TAB.FIRST_RCPT) > 0 AND SUM(TAB.FIRST_SOLVE) > 0 THEN ROUND((CAST(SUM(TAB.FIRST_SOLVE) AS FLOAT) / CAST(SUM(TAB.FIRST_RCPT) AS FLOAT)) * 100, 0) ELSE 0 END) AS FIRST_RATE FROM ( SELECT A.ClientID AS CORP_ID, MAX(A.ClientName) AS CORP_NAME , A.SRArea1 AS svc_ci_id1 , A.SRArea2 AS svc_ci_id2 , MAX(A.SRArea2Name) AS svc_ci_name , MAX(A.SRArea1Name) AS svc_ci_name1 , A.ReqCompanyID AS REQ_companycode , MAX(A.ReqCompanyName) AS REQ_companyNAME , MAX(A.RequestTeamID) AS RequestTeamID , SUM(CASE WHEN A.Category = 'RCP000' THEN 1 ELSE 0 END ) DS_REQ1 , SUM(CASE WHEN A.Category = 'RCP010' THEN 1 ELSE 0 END ) DS_REQ2 , SUM(CASE WHEN A.Category IN( 'RCP020','RCP030') THEN 1 ELSE 0 END ) DS_REQ3 ,0 DS_APP ,0 DS_DATA ,0 DS_INFRA ,0 DS_SCM ,0 DS_INC ,0 DS_WORK ,SUM(CASE WHEN A.ActivityLastStatus NOT IN ('04','06','08','09','07') AND ISNULL(A.CompletionDT, '') != '' THEN 1 ELSE 0 END) AS CNTCOMPLETE ,SUM(CASE WHEN A.ActivityLastStatus NOT IN ('04','06','08','09','07') AND ISNULL(A.CompletionDT, '') != '' THEN CASE WHEN A.DueDate IS NULL THEN 1 ELSE CASE WHEN DATEDIFF(DAY, ISNULL(A.DueDate, A.CompletionDT), ISNULL(A.WORK_DATE, '1900-01-01')) < 0 THEN 0 ELSE 1 END END ELSE 0 END) CNTCOMPLETE_DUE ,SUM(CASE WHEN A.REQ0002ActorID is not null THEN 1 ELSE 0 END) AS FIRST_RCPT ,SUM(CASE WHEN A.REQ0002ActorID is not null AND A.REQ0004ActorID IS NULL THEN 1 ELSE 0 END) AS FIRST_SOLVE
FROM XBOLTAPP.VW_ESM_SR_REQUEST A WITH(NOLOCK) where CONVERT(DATE, A.RegDT) BETWEEN #{stSRReqDT} AND #{endSRReqDT} AND NOT EXISTS (SELECT 'x' FROM XBOLTDLM.RELATIONS b WITH(NOLOCK) WHERE b.HIGH_ID = A.SRCode ) AND A.ActivityLastStatus NOT IN ('04','06','08','09','07') AND A.SVC_CI_ID NOT IN ('ALL_SVC_001')
AND A.ClientID = #{customerNo}
AND A.ClientID in ( SELECT ClientID FROM XBOLTADM.TB_PROJECT TP left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR on TP.ProjectID = TPMR.ProjectID Where TPMR.MemberID = #{userID} And TP.ProjectType = 'CSR' )
AND A.SRArea1 = #{srArea1}
AND A.SRArea2 = #{srArea2}
AND A.REQ0004ActorID IS NULL AND A.REQ0002ActorID IS NOT null
AND REQ0004ActorID IS NOT NULL
And A.ProjectID in ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP WITH(NOLOCK) left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR WITH(NOLOCK) on TP.ProjectID = TPMR.ProjectID Where TPMR.MemberID = #{userID} And TP.ProjectType = 'CSR' )
GROUP BY A.ClientID, A.SRArea1, A.SRArea2,A.ReqCompanyID /* 추가 요청자 회사 추가*/
UNION ALL
SELECT VSP.ClientID AS CORP_ID, MAX(VSP.ClientName) AS CORP_NAME, VSP.SRArea1 AS svc_ci_id1, VSP.SRArea2 AS svc_ci_id2, MAX(VSP.SRArea2Name) AS svc_ci_name, MAX(VSP.SRArea1Name) AS svc_ci_name1, VSP.ReqCompanyID AS REQ_companycode, VSP.ReqCompanyName AS REQ_companyNAME, MAX(VSP.RequestTeamID) AS RequestTeamID, 0, 0, 0,
SUM(CASE WHEN VSP.SRType = 'ACM' THEN 1 ELSE 0 END) AS DS_APP, SUM(CASE WHEN VSP.SRType = 'DCM' THEN 1 ELSE 0 END) AS DS_DATA, SUM(CASE WHEN VSP.SRType = 'ICM' THEN 1 ELSE 0 END) AS DS_INFRA, SUM(CASE WHEN VSP.SRType = 'SCM' THEN 1 ELSE 0 END) AS DS_SCM, SUM(CASE WHEN VSP.SRType = 'INC' THEN 1 ELSE 0 END) AS DS_INC, SUM(CASE WHEN VSP.SRType = 'WRK' THEN 1 ELSE 0 END) AS DS_WORK, SUM(CASE WHEN VSP.ActivityLastStatus NOT IN ('04','06','08','09','07') AND ISNULL(VSP.CompletionDT, '') != '' THEN 1 ELSE 0 END) AS CNTCOMPLETE,
SUM(CASE WHEN VSP.SRTYPE = 'WRK' THEN 1 ELSE CASE WHEN VSP.ActivityLastStatus NOT IN ('04','06','08','09','07') AND ISNULL(VSP.CompletionDT, '') != '' THEN CASE WHEN DATEDIFF(DAY, ISNULL(VSP.DueDate, VSP.CompletionDT), ISNULL(VSP.WORK_DATE, '1900-01-01')) < 0 THEN 0 ELSE 1 END ELSE 0 END END ) CNTCOMPLETE_DUE, /* 기한내 완료 건수*/
0, 0 FROM XBOLTAPP.VW_ESM_SR_MST VSP WITH(NOLOCK) WHERE CONVERT(DATE, VSP.RegDT) BETWEEN #{stSRReqDT} AND #{endSRReqDT} AND VSP.SRType NOT IN ('REQ') AND NOT EXISTS ( SELECT 1 FROM XBOLTDLM.RELATIONS b WITH(NOLOCK) WHERE b.HIGH_ID = VSP.SRCode AND VSP.SRType = 'REQ' ) AND VSP.ActivityLastStatus NOT IN ('04','06','08','09','07' )
AND VSP.ClientID = #{customerNo}
AND VSP.ClientID in (SELECT ClientID FROM XBOLTADM.TB_PROJECT TP left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR on TP.ProjectID = TPMR.ProjectID Where TPMR.MemberID = #{userID} And TP.ProjectType = 'CSR')
AND VSP.SRArea1 = #{srArea1}
AND VSP.SRArea2 = #{srArea2}
And VSP.ProjectID in ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP WITH(NOLOCK) left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR WITH(NOLOCK) on TP.ProjectID = TPMR.ProjectID Where TPMR.MemberID = #{userID} And TP.ProjectType = 'CSR' )
GROUP BY VSP.ClientID, VSP.SRArea1, VSP.SRArea2, VSP.ReqCompanyID, VSP.ReqCompanyName
) TAB GROUP BY TAB.corp_id,TAB.svc_ci_id1, TAB.svc_ci_id2,TAB.REQ_companycode /* 추가 요청자 회사 추가*/ ORDER BY TAB.corp_id,TAB.svc_ci_id1, TAB.svc_ci_id2,TAB.REQ_companycode /* 추가 요청자 회사 추가*/

Select ROW_NUMBER() OVER (ORDER BY TAB.RegDT) AS RNUM , TAB.SRID, TAB.SRCode , TAB.ClientName, TAB.SRTypeNM , TAB.Subject, TAB.SRArea1Name, TAB.SRArea2Name, TAB.CategoryNM, TAB.SubCategoryNM , TAB.RequestUserNM, TAB.ReqCompanyName , TAB.RCPT_USERID, CONVERT(char(10),TAB.RCPT_DATE, 120) AS RCPT_DATE , TAB.RCPT_NM, CONVERT(char(10),TAB.RegDT, 120) AS RegDT, CONVERT(char(10),TAB.DueDate, 120) AS DueDate , CONVERT(char(10),TAB.CompletionDT,120) AS CompletionDT , TAB.StatusName AS StatusName , DATEDIFF(DAY, TAB.DueDate, TAB.CompletionDT) AS DelayCNT From ( Select A.SRID,A.SRcode , A.ClientName, TD.Name AS SRTypeNM , A.Subject, A.SRArea1Name, A.SRArea2Name, TD2.Name AS CategoryNM, TD3.Name AS SubCategoryNM , TM.Name AS RequestUserNM, A.ReqCompanyName , A.REQ0002ActorID AS RCPT_USERID, A.RCPT_DATE AS RCPT_DATE , TM2.Name AS RCPT_NM, A.RegDT, A.DueDate, A.CompletionDT, A.StatusName FROM XBOLTAPP.VW_ESM_SR_REQUEST A WITH(NOLOCK) INNER JOIN XBOLTADM.TB_MEMBER TM WITH(NOLOCK) ON TM.MemberID = A.RequestUserID Left Outer JOIN XBOLTADM.TB_MEMBER TM2 WITH(NOLOCK) ON TM2.MemberID = A.REQ0002ActorID INNER JOIN XBOLTADM.TB_DICTIONARY TD WITH(NOLOCK) ON TD.TypeCode = A.SRType AND TD.Category = 'SRTP' AND TD.LanguageID = #{languageID} Left Outer JOIN XBOLTADM.TB_DICTIONARY TD2 WITH(NOLOCK) ON TD2.TypeCode = A.Category AND TD2.Category = 'SRCAT' AND TD2.LanguageID = #{languageID} Left Outer JOIN XBOLTADM.TB_DICTIONARY TD3 WITH(NOLOCK) ON TD3.TypeCode = A.SubCategory AND TD3.Category = 'SRCAT' AND TD3.LanguageID = #{languageID} WHERE CONVERT(DATE, A.RegDT) BETWEEN #{regStartDate} AND #{regEndDate} AND NOT EXISTS ( SELECT 'x' FROM XBOLTDLM.RELATIONS b WITH(NOLOCK) WHERE b.HIGH_ID = A.SRCode ) AND A.ClientID = #{clientID} AND A.ActivityLastStatus NOT IN ('04', '06', '08', '09','07') AND A.SVC_CI_ID NOT IN ('ALL_SVC_001') AND A.SRArea1 = #{srArea1} AND A.SRArea2 = #{srArea2}
AND A.ReqCompanyID = #{reqCompanyID}
AND A.ProjectID IN ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP WITH(NOLOCK) LEFT OUTER JOIN XBOLTADM.TB_PJT_MEMBER_REL TPMR WITH(NOLOCK) ON TP.ProjectID = TPMR.ProjectID WHERE TPMR.MemberID = #{sessionUserID} AND TP.ProjectType = 'CSR' )
UNION ALL
Select VSP.SRID, VSP.SRCODE , VSP.ClientName, TD.Name AS SRTypeNM , VSP.Subject, VSP.SRArea1Name, VSP.SRArea2Name, TD2.Name AS CategoryNM, TD3.Name AS SubCategoryNM , TM.Name AS RequestUserNM, VSP.ReqCompanyName , VSP.RCPT_USERID AS RCPT_USERID, VSP.RCPT_DATE AS RCPT_DATE , TM2.Name AS RCPT_NM, VSP.RegDT,VSP.DueDate, VSP.CompletionDT, VSP.StatusName
From XBOLTAPP.VW_ESM_SR_MST VSP INNER JOIN XBOLTADM.TB_MEMBER TM WITH(NOLOCK) ON TM.MemberID = VSP.RequestUserID Left Outer JOIN XBOLTADM.TB_MEMBER TM2 WITH(NOLOCK) ON TM2.MemberID = VSP.RCPT_USERID INNER JOIN XBOLTADM.TB_DICTIONARY TD WITH(NOLOCK) ON TD.TypeCode = VSP.SRType AND TD.Category = 'SRTP' AND TD.LanguageID = #{languageID} Left Outer JOIN XBOLTADM.TB_DICTIONARY TD2 WITH(NOLOCK) ON TD2.TypeCode = VSP.Category AND TD2.Category = 'SRCAT' AND TD2.LanguageID = #{languageID} Left Outer JOIN XBOLTADM.TB_DICTIONARY TD3 WITH(NOLOCK) ON TD3.TypeCode = VSP.SubCategory AND TD3.Category = 'SRCAT' AND TD3.LanguageID = #{languageID} Where CONVERT(DATE, VSP.RegDT) BETWEEN #{regStartDate} AND #{regEndDate} AND VSP.SRType NOT IN ('REQ') AND NOT EXISTS ( SELECT 1 FROM XBOLTDLM.RELATIONS b WITH(NOLOCK) WHERE b.HIGH_ID = VSP.SRCode AND VSP.SRType = 'REQ' ) AND VSP.ActivityLastStatus NOT IN ('04', '06', '08', '09','07') AND VSP.SRArea1 = #{srArea1} AND VSP.SRArea2 = #{srArea2}
AND VSP.ReqCompanyID = #{reqCompanyID}
AND VSP.ClientID = #{clientID} AND VSP.ProjectID IN ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP WITH(NOLOCK) LEFT OUTER JOIN XBOLTADM.TB_PJT_MEMBER_REL TPMR WITH(NOLOCK) ON TP.ProjectID = TPMR.ProjectID WHERE TPMR.MemberID = #{sessionUserID} AND TP.ProjectType = 'CSR' ) ) TAB

SELECT TOP 0 MemberID,Name INTO #TB_MEMBER_tmp FROM XBOLTADM.TB_MEMBER
CREATE CLUSTERED INDEX ix ON #TB_MEMBER_tmp(MemberID)
INSERT INTO #TB_MEMBER_tmp SELECT MemberID,Name FROM XBOLTADM.TB_MEMBER
SELECT ROW_NUMBER() OVER (ORDER BY TSM.ClientID, EMR.WORK_DATE DESC) AS RowNum ,TSM.ClientID , TXT.Name ClientName , TSM.SRCode , TD.Name TypeName , TD1.Name + '>' + TD2.Name As CategoryNM , TSM.Subject , TSM.Description , EMR.SpeCode , TIA.PlainText SRStatusName , EMR.MemberID ReceiptUserID , TM.Name ReceiptUserName , CONVERT(varchar(10), EMR.WORK_DATE, 120) WORK_DATE , CONVERT(varchar(10), TSM.DueDate, 120) DueDate , TSM.CompletionDT , EMR.BUSINESS_HOURS as BUSINESS_HOUR , EMR.OVERTIME , ( EMR.BUSINESS_HOURS + EMR.OVERTIME ) AS WORK_TIME_MM , CONVERT(VARCHAR(50), EMR.BUSINESS_HOURS) + '/' + CONVERT(VARCHAR(50), EMR.OVERTIME) AS PROCESS_DATE FROM XBOLTAPP.ESM_MBR_RCD EMR WITH(NOLOCK) LEFT OUTER JOIN XBOLTAPP.ESM_SR_MST TSM WITH(NOLOCK) ON EMR.SRID = TSM.SRID --LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM WITH(NOLOCK) ON TM.MemberID = EMR.MemberID LEFT OUTER JOIN #TB_MEMBER_tmp TM WITH(NOLOCK) ON TM.MemberID = EMR.MemberID LEFT OUTER JOIN XBOLTADM.TB_TEAM TT WITH(NOLOCK) ON TT.ClientID = TSM.ClientID AND TT.TeamType = 2 LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TXT WITH(NOLOCK) ON TXT.TeamID = TT.TeamID And TXT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD WITH(NOLOCK) ON TD.TypeCode = TSM.SRType AND TD.LanguageID = #{languageID} AND TD.Category = 'SRTP' LEFT OUTER JOIN XBOLTADM.TB_ITEM TI WITH(NOLOCK) ON EMR.SpeCode = TI.Identifier LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TIA.ItemID = TI.ItemID And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD1 WITH(NOLOCK) On TD1.TypeCode = TSM.Category AND TD1.Category = 'SRCAT' And TD1.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD2 WITH(NOLOCK) On TD2.TypeCode = TSM.SubCategory And TD2.Category = 'SRCAT' And TD2.LanguageID = #{languageID}
WHERE (EMR.BUSINESS_HOURS + EMR.OVERTIME) > 0
AND TSM.ClientID = #{customerNo}
And TSM.ProjectID in ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP WITH(NOLOCK) left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR WITH(NOLOCK) on TP.ProjectID = TPMR.ProjectID Where TPMR.MemberID = #{userID} And TP.ProjectType = 'CSR' )
And EMR.WORK_DATE BETWEEN CAST(#{startDate} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{endDate} AS DATETIME)))
AND EMR.MemberID = #{receiptUserID}
DROP TABLE #TB_MEMBER_tmp

Select ROW_NUMBER() OVER (ORDER BY B.CORP_ID, B.USER_NM) AS RowNum, B.CORP_ID AS CORP_ID, B.CODE_NM AS CODE_NM, B.CD_DEPT AS CD_DEPT, B.DS_DEPT AS DS_DEPT, A.USR_ID AS STEP_MNG_ID, B.EmployeeNum AS EmployeeNum, B.USER_NM AS STEP_MNG_NM, A.TOT_CNT AS TOT_CNT, A.DELAY_CNT AS DELAY_CNT, CASE WHEN A.TOT_CNT = 0 OR A.DELAY_CNT = 0 THEN 0 ELSE ROUND((CAST(A.DELAY_CNT AS FLOAT) / CAST(A.TOT_CNT AS FLOAT)) * 100, 2) END AS DELAY_RATE, B.BIZ_NM AS BIZ_NM, B.DAECO_YN AS DAECO_YN From ( Select
EMR.MemberID AS USR_ID, EMR.ProjectID, COUNT(*) AS TOT_CNT, SUM(CASE WHEN CAST(CONVERT(varchar(10), ESA.Value, 120) AS DATE) < CAST(CONVERT(varchar(10), EAL.EndTime, 120) AS DATE) THEN 1 ELSE 0 END) AS DELAY_CNT From ( Select SRID,SpeCode,MemberID,ProjectID FROM XBOLTAPP.VW_ESM_MBR_RCD WITH(NOLOCK) WHERE CONVERT(varchar(10), WORK_DATE , 120) BETWEEN #{startDate} AND #{endDate}
And ClientID = #{customerNo}
GROUP BY SRID,SpeCode,MemberID,ProjectID ) EMR Left Outer Join XBOLTAPP.ESM_ACTIVITY_LOG EAL WITH(NOLOCK) ON EAL.PID = EMR.SRID And EAL.SpeCode = EMR.SpeCode Left Outer Join XBOLTAPP.ESM_SR_ATTR ESA WITH(NOLOCK) ON ESA.AttrTypeCode ='SRAT0069' And ESA.SRID = EMR.SRID And ESA.SpeCode = EMR.SpeCode
Group By EMR.MEMBERID, EMR.ProjectID ) A Left Outer Join ( SELECT IDI.MemberID AS USR_ID, MAX(TT.Inhouse) AS DAECO_YN, MAX(TMT.Name) AS BIZ_NM, MAX(IDI.USER_NM) AS USER_NM, MAX(IDI.CD_DEPT) AS CD_DEPT, MAX(IDI.NM_DEPT) AS DS_DEPT, MAX(IDI.CORP_ID) AS CORP_ID, MAX(TRIM(CORP_NAME)) AS CODE_NM, MAX(TM.EmployeeNum) AS EmployeeNum, MAX(T.TeamID) AS TeamID FROM XBOLTDLM.ITUSER_DEPT_INFO IDI WITH(NOLOCK) LEFT Outer JOIN XBOLTADM.TB_TEAM TT WITH(NOLOCK) ON IDI.BIZ_KEY = TT.TeamCode And TT.TeamType = 54 Left Outer Join XBOLTADM.TB_TEAM_TXT TMT WITH(NOLOCK) ON TMT.TeamID = TT.TeamID And TMT.LanguageID=#{languageID} Left Outer JOIN XBOLTADM.TB_TEAM T WITH(NOLOCK) ON IDI.CD_DEPT = T.TeamCode And T.Deleted != 1 Left Outer Join XBOLTADM.TB_MEMBER TM WITH(NOLOCK) ON TM.MemberID = IDI.MemberID GROUP BY IDI.MemberID ) B ON A.USR_ID = B.USR_ID WHERE 1 = 1 AND NOT EXISTS ( SELECT 1 FROM XBOLTADM.TB_MEMBER WITH(NOLOCK) WHERE MemberID = A.USR_ID AND ISNULL(Active, '') = '0' ) And A.USR_ID IS NOT NULL
And B.CORP_ID IN( select RefTeamCode From XBOLTADM.TB_TEAM WITH(NOLOCK) WHERE TeamID IN (select TeamID from XBOLTAPP.CRM_CUST_MST Where CustomerNo = #{customerNo} ))
And B.TeamID = #{teamID}
AND A.ProjectID IN ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP WITH(NOLOCK) LEFT OUTER JOIN XBOLTADM.TB_PJT_MEMBER_REL TPMR WITH(NOLOCK) ON TP.ProjectID = TPMR.ProjectID WHERE TPMR.MemberID = #{userID} AND TP.ProjectType = 'CSR' )

SELECT ROW_NUMBER() OVER (ORDER BY VWPWDB.SRType,VWPWDB.SRcode,VWPWDB.SpeCode,VWPWDB.WORK_DATE ) AS RowNum , VWPWDB.SRType AS TBL , TD.Name AS TBL_NM , VWPWDB.SRcode AS ID , VWPWDB.Subject AS TITLE , VWPWDB.SpeCode AS PROCESS_STEP_ID , TIA.PlainText AS PROCESS_STEP_NM , ISNULL(CONVERT(char(10),VWPWDB.WORK_DATE, 120),'') AS WORK_DATE , VWPWDB.WEEKEND , ( VWPWDB.BUSINESS_HOURS + VWPWDB.OVERTIME ) AS WORK_TIME_MM , VWPWDB.HOLYDAY , VWPWDB.Description FROM XBOLTAPP.VW_ESM_MBR_RCD VWPWDB WITH(NOLOCK) Left Outer Join XBOLTADM.TB_DICTIONARY TD WITH(NOLOCK) On TD.TypeCode = VWPWDB.SRType And TD.Category = 'SRTP' And TD.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM TI WITH(NOLOCK) ON VWPWDB.SpeCode = TI.Identifier Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TIA.ItemID = TI.ItemID And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} WHERE (VWPWDB.BUSINESS_HOURS + VWPWDB.OVERTIME) > 0 AND VWPWDB.MemberID = #{memberID} AND CONVERT(varchar(10), VWPWDB.WORK_DATE , 120) BETWEEN #{startDate} AND #{endDate} AND ISNULL(VWPWDB.SRArea1,'') != ''
And VWPWDB.SRArea2 = #{srArea2}
AND VWPWDB.ProjectID IN ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP WITH(NOLOCK) LEFT OUTER JOIN XBOLTADM.TB_PJT_MEMBER_REL TPMR WITH(NOLOCK) ON TP.ProjectID = TPMR.ProjectID WHERE TPMR.MemberID = #{userID} AND TP.ProjectType = 'CSR' )

select MAX(SRTypeNM) AS GUBUN , SRCode AS SRCode , MAX(ClientID) AS ClientID , MAX(srAreaNM) AS srAreaNM , MAX(RequestUserID) as RequestUserID , MAX(RequserUserNM) as RequserUserNM , MAX(RequestUserEmail) as RequestUserEmail , MAX(Subject) AS Subject , MAX(RCPTDATE) AS RCPTDATE , MAX(ReqDueDate) AS ReqDueDate , MAX(CompletionDT) AS CompletionDT , ISNULL(MAX(SCORE1),0) AS SCORE1 , ISNULL(MAX(SCORE2),0) AS SCORE2 , max(instid) as instid , max(SRID) as SRID , max(SRType) as SRType , max(ESType) as ESType , max(Status) as Status , max(ReceiptUserID) as receiptUserID FROM ( select TD1.Name AS SRTypeNM , ESM.SRCode , ESM.ClientID , TIA1.PlainText + CASE WHEN ISNULL(TIA2.PlainText,'') = '' THEN '' ELSE ' > ' + TIA2.PlainText END AS srAreaNM , TM1.LoginID RequestUserID , TM1.Name RequserUserNM , ESM.Subject , ISNULL(FORMAT(EAL.StartTime, 'yyyy-MM-dd'),' ') RCPTDATE , ISNULL(FORMAT(ESM.ReqDueDate, 'yyyy-MM-dd'),' ') ReqDueDate , ISNULL(FORMAT(ESM.CompletionDT, 'yyyy-MM-dd'),' ') AS CompletionDT , ISNULL(EEIV1.Value,0) as SCORE1 , ISNULL(EEIV2.Value,0) as SCORE2 , '' as instid , TM1.Email RequestUserEmail , ESM.SRID , ESM.SRType, ESM.ESType, ESM.Status, ESM.ReceiptUserID FROM XBOLTAPP.ESM_SR_MST ESM WITH(NOLOCK) INNER JOIN XBOLTAPP.ESM_EVAL_SHEET EES WITH(NOLOCK) ON EES.DocumentID = ESM.SRID INNER JOIN XBOLTAPP.ESM_EVAL_ITEM_VALUE EEIV1 WITH(NOLOCK) ON EEIV1.EvalSheetID = EES.EvalSheetID AND EEIV1.AttrTypeCode = 'EVAT001' INNER JOIN XBOLTAPP.ESM_EVAL_ITEM_VALUE EEIV2 WITH(NOLOCK) ON EEIV2.EvalSheetID = EES.EvalSheetID AND EEIV2.AttrTypeCode = 'EVAT002' INNER JOIN XBOLTADM.TB_MEMBER TM1 WITH(NOLOCK) ON TM1.MemberID = ESM.RequestUserID INNER JOIN XBOLTADM.TB_TEAM_TXT TTT1 WITH(NOLOCK) ON TTT1.TeamID = TM1.TeamID AND TTT1.LanguageID = #{languageID}
INNER JOIN XBOLTADM.TB_DICTIONARY TD1 WITH(NOLOCK) ON TD1.TypeCode = ESM.SRType AND TD1.LanguageID = #{languageID} AND TD1.Category = 'SRTP' LEFT OUTER JOIN XBOLTADM.TB_ITEM TI1 WITH(NOLOCK) ON TI1.ItemID = ESM.SRArea1 LEFT OUTER JOIN XBOLTADM.TB_ITEM TI2 WITH(NOLOCK) ON TI2.ItemID = ESM.SRArea2 LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA1 WITH(NOLOCK) ON TIA1.ItemID = TI1.ItemID AND TIA1.LanguageID = #{languageID} AND TIA1.AttrTypeCode = 'AT00001' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA2 WITH(NOLOCK) ON TIA2.ItemID = TI2.ItemID AND TIA2.LanguageID = #{languageID} AND TIA2.AttrTypeCode = 'AT00001' LEFT OUTER JOIN XBOLTAPP.ESM_MBR_RCD EMR WITH(NOLOCK) ON EMR.SRID = ESM.SRID LEFT OUTER JOIN XBOLTAPP.ESM_ACTIVITY_LOG EAL WITH(NOLOCK) ON EAL.PID = ESM.SRID AND EAL.ActivityLogID = ( SELECT MAX(ActivityLogID) FROM XBOLTAPP.ESM_ACTIVITY_LOG WHERE SpeCode != 'ZSPE00' AND PID = ESM.SRID ) WHERE ESM.SRType != 'WRK' AND ESM.Blocked = '2' AND ESM.Status = 'ZSPE00' And EMR.WORK_DATE BETWEEN CAST(#{startDate} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{endDate} AS DATETIME))) AND ESM.ClientID = #{customerNo}
And ESM.ProjectID in ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR on TP.ProjectID = TPMR.ProjectID Where TPMR.MemberID = #{userID} And TP.ProjectType = 'CSR' )
AND (EEIV1.Value IN (${happyTypeList}) OR EEIV2.Value IN (${happyTypeList})) )T group by SRCode

select MAX(SRTypeNM) AS GUBUN , SRCode AS SRCode , MAX(ClientID) AS ClientID , MAX(srAreaNM) AS srAreaNM , MAX(RequestUserTeamNM) AS RequestUserTeamNM , MAX(RequestUserID) as RequestUserID , MAX(RequserUserNM) as RequserUserNM , MAX(RequestUserEmail) as RequestUserEmail , MAX(Subject) AS Subject , MAX(RCPTDATE) AS RCPTDATE , MAX(ReqDueDate) AS ReqDueDate , MAX(CompletionDT) AS CompletionDT , ISNULL(MAX(SCORE1),0) AS SCORE1 , ISNULL(MAX(SCORE2),0) AS SCORE2 , max(instid) as instid , MAX(saSurveyDesc) as saSurveyDesc , max(SRID) as SRID , max(SRType) as SRType , max(ESType) as ESType , max(Status) as Status , max(ReceiptUserID) as receiptUserID FROM ( select TD1.Name AS SRTypeNM , ESM.SRCode , ESM.ClientID , TIA1.PlainText + CASE WHEN ISNULL(TIA2.PlainText,'') = '' THEN '' ELSE ' > ' + TIA2.PlainText END AS srAreaNM , TM1.LoginID RequestUserID , TM1.Name RequserUserNM , TTT1.Name RequestUserTeamNM , ESM.Subject , ISNULL(FORMAT( ( SELECT TOP 1 StartTime FROM XBOLTAPP.ESM_ACTIVITY_LOG WITH (NOLOCK) WHERE SpeCode != 'ZSPE00' AND pid = ESM.SRID ORDER BY ActivityLogID DESC ), 'yyyy-MM-dd'),' ') RCPTDATE , ISNULL(FORMAT(ESM.ReqDueDate, 'yyyy-MM-dd'),' ') ReqDueDate , ISNULL(FORMAT(ESM.CompletionDT, 'yyyy-MM-dd'),' ') AS CompletionDT , ISNULL(EEIV1.Value,0) as SCORE1 , ISNULL(EEIV2.Value,0) as SCORE2 , '' as instid , TM1.Email RequestUserEmail , EEIV3.Value as saSurveyDesc , ESM.SRID , ESM.SRType, ESM.ESType, ESM.Status, ESM.ReceiptUserID FROM XBOLTAPP.ESM_SR_MST ESM WITH(NOLOCK) INNER JOIN XBOLTAPP.ESM_MBR_RCD EMR WITH(NOLOCK) ON EMR.SRID = ESM.SRID INNER JOIN XBOLTAPP.ESM_EVAL_SHEET EES WITH(NOLOCK) ON EES.DocumentID = ESM.SRID INNER JOIN XBOLTAPP.ESM_EVAL_ITEM_VALUE EEIV1 WITH(NOLOCK) ON EEIV1.EvalSheetID = EES.EvalSheetID AND EEIV1.AttrTypeCode = 'EVAT001' INNER JOIN XBOLTAPP.ESM_EVAL_ITEM_VALUE EEIV2 WITH(NOLOCK) ON EEIV2.EvalSheetID = EES.EvalSheetID AND EEIV2.AttrTypeCode = 'EVAT002' INNER JOIN XBOLTAPP.ESM_EVAL_ITEM_VALUE EEIV3 WITH(NOLOCK) ON EEIV3.EvalSheetID = EES.EvalSheetID AND EEIV3.AttrTypeCode = 'EVAT003' AND EEIV3.Value != '' INNER HASH JOIN XBOLTADM.TB_MEMBER TM1 WITH(NOLOCK) ON TM1.MemberID = ESM.RequestUserID INNER JOIN XBOLTADM.TB_TEAM_TXT TTT1 WITH(NOLOCK) ON TTT1.TeamID = TM1.TeamID AND TTT1.LanguageID = #{languageID}
INNER JOIN XBOLTADM.TB_DICTIONARY TD1 WITH(NOLOCK) ON TD1.TypeCode = ESM.SRType AND TD1.LanguageID = #{languageID} AND TD1.Category = 'SRTP' LEFT OUTER JOIN XBOLTADM.TB_ITEM TI1 WITH(NOLOCK) ON TI1.ItemID = ESM.SRArea1 LEFT OUTER JOIN XBOLTADM.TB_ITEM TI2 WITH(NOLOCK) ON TI2.ItemID = ESM.SRArea2 LEFT OUTER HASH JOIN XBOLTADM.TB_ITEM_ATTR TIA1 WITH(NOLOCK) ON TIA1.ItemID = TI1.ItemID AND TIA1.LanguageID = #{languageID} AND TIA1.AttrTypeCode = 'AT00001' LEFT OUTER HASH JOIN XBOLTADM.TB_ITEM_ATTR TIA2 WITH(NOLOCK) ON TIA2.ItemID = TI2.ItemID AND TIA2.LanguageID = #{languageID} AND TIA2.AttrTypeCode = 'AT00001' WHERE ESM.SRType != 'WRK' AND ESM.Blocked = '2' AND ESM.Status = 'ZSPE00' AND ESM.ClientID = #{customerNo}
And ESM.ProjectID in ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR WITH(NOLOCK) on TP.ProjectID = TPMR.ProjectID Where TPMR.MemberID = #{userID} And TP.ProjectType = 'CSR' )
And EMR.WORK_DATE BETWEEN CAST(#{startDate} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{endDate} AS DATETIME))) ) T group by SRCode

Select Top 1000 Row_Number()OVER(ORDER BY TBD.RegDTOrg DESC ) as RNUM, TBD.* From( Select TSM.SRID, TSM.SRCode, TSM.SRType, TSM.ESType, TD5.Name AS SRTypeNM, TSM.ProcRoleTP, TEAM6.Name AS CompanyName, TSM.ClientID,TSM.ProjectID, TSM.Subject, TSM.Description, TSM.ProcPathID, TSM.SRArea1, TIA.PlainText As SRArea1Name, TSM.SRArea2, TIA2.PlainText As SRArea2Name, TSM.Category, TD4.Name As CategoryNM, TSM.SubCategory, ISNULL(TD3.Name, TD4.Name) As SubCategoryNM, TSM.Status, TISA.PlainText As StatusName, TSM.RegUserID, TM2.Name As RegUserName, TSM.RegTeamID, TEAM1.Name As RegTeamName, ISNULL(CONVERT(char(10),TSM.RegDT, 120),'') as RegDate, TSM.RequestUserID, TM3.Name As ReqUserNM, TSM.RequestTeamID, TEAM2.Name As ReqTeamNM, ISNULL(CONVERT(char(10),TSM.DueDate, 120),'') as SRDueDate, ISNULL(CONVERT(char(10),TSM.ReqDueDate, 120),'') as ReqDueDate, TSM.ReceiptUserID, TM4.Name As ReceiptName, TSM.ReceiptTeamID, TEAM3.Name As ReceiptTeamName, TM4.Name + '(' + TEAM3.Name + ')' as ReceiptInfo, TM3.Name + '(' + TEAM2.Name + ')' as RequestInfo, TSM.ResponseUserID, TM5.Name As ResponseUserName, TSM.ResponseTeamID, TEAM4.Name As ResponseTeamName, TM5.Name + '(' + TEAM4.Name + ')' as ResponseInfo, ISNULL(CONVERT(char(10),TSM.CompletionDT, 120),'') as SRCompletionDT,
TSM.RegDT As RegDTOrg, TSM.ReqDueDate AS ReqDueDateOrg, TSM.DueDate as DueDateOrg, TSM.CompletionDT As CompletionDTOrg, TSM.CompanyID, TSM.ReceiptTeamID As SRReceiptTeamID, Case When CompletionDT IS NULL Then 'N' Else 'Y' End AS SvcCompl,
ReceiptDelay = CASE WHEN TSM.Duedate is null THEN CASE WHEN CONVERT(INT, DATEDIFF(HH, TSM.RegDT, GETDATE())) >= 12 THEN 'Y' ELSE 'N' END ELSE 'N' END, CompletionDelay = CASE WHEN TSM.CompletionDT is null THEN CASE WHEN TSM.Duedate < GETDATE() THEN 'Y' ELSE 'N' END WHEN TSM.CompletionDT is not null THEN CASE WHEN TSM.Duedate < tsm.CompletionDT THEN 'Y' ELSE 'N' END END, TI.Identifier AS ItemCode, TIA3.PlainText AS ItemName, TSM.ItemTypeCode, ISNULL(TD2.Name, TD6.Name) AS ItemTypeCodeNM, TI.Identifier+' '+TIA3.PlainText+' ('+TIA.PlainText+'/'+TIA2.PlainText+')' AS ItemInfo, TIA.PlainText+'/'+TIA2.PlainText AS SRAreaNM, TD8.Name AS ProcRoleTypeName, XBOLTAPP.fn_GetESPRoleTPMemberList(TSM.ProcRoleTP, CASE WHEN (TSM.SRArea2 IS NULL OR TSM.SRArea2 = '' OR TSM.SRArea2 = '0') THEN TSM.SRArea1 ELSE TSM.SRArea2 END ) AS ProcRoleTypeMemberList, TSM.isPublic, TMT.Name AS RequestCompanyName, CASE WHEN ISNULL(TSM.ReceiptUserID,'') != '' THEN (Select Top 1 ISNULL(CONVERT(char(10),StartTime, 120),'') From XBOLTAPP.ESM_ACTIVITY_LOG Where PID = TSM.SRID ORDER BY ActivityLogID) ELSE NULL END AS ReceiptDate, CASE WHEN TSM.DueDate < GETDATE() AND TSM.CompletionDT IS NULL THEN DATEDIFF(DAY, TSM.DueDate, GETDATE()) WHEN TSM.CompletionDT IS NOT NULL THEN Case When DATEDIFF(DAY, TSM.CompletionDT, TSM.DueDate) IS NULL THEN 0 ELSE DATEDIFF(DAY, TSM.CompletionDT, TSM.DueDate) END ELSE 0 END AS CompletionDelayDays
From XBOLTAPP.ESM_SR_MST TSM WITH(NOLOCK) Left Outer Join XBOLTADM.TB_MEMBER TM2 WITH(NOLOCK) On TM2.MemberID = TSM.RegUserID Left Outer Join XBOLTADM.TB_MEMBER TM3 WITH(NOLOCK) On TM3.MemberID = TSM.RequestUserID Left Outer Join XBOLTADM.TB_MEMBER TM4 WITH(NOLOCK) On TM4.MemberID = TSM.ReceiptUserID Left Outer Join XBOLTADM.TB_MEMBER TM5 WITH(NOLOCK) On TM5.MemberID = TSM.ResponseUserID
Left Outer Join XBOLTADM.TB_DICTIONARY TD4 WITH(NOLOCK) On TD4.TypeCode = TSM.Category AND TD4.Category = 'SRCAT' And TD4.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD3 WITH(NOLOCK) On TD3.TypeCode = TSM.SubCategory And TD3.Category = 'SRCAT' And TD3.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_ITEM TIS WITH(NOLOCK) ON TSM.Status = TIS.Identifier Left Outer Join XBOLTADM.TB_ITEM_ATTR TISA WITH(NOLOCK) ON TISA.ItemID = TIS.ItemID And TISA.AttrTypeCode = 'AT00001' And TISA.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM1 WITH(NOLOCK) ON TEAM1.TeamID = TSM.RegTeamID And TEAM1.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM2 WITH(NOLOCK) ON TEAM2.TeamID = TSM.RequestTeamID And TEAM2.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM3 WITH(NOLOCK) ON TEAM3.TeamID = TSM.ReceiptTeamID And TEAM3.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM4 WITH(NOLOCK) ON TEAM4.TeamID = TSM.ResponseTeamID And TEAM4.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TIA.ItemID = TSM.SRArea1 And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA2 WITH(NOLOCK) ON TIA2.ItemID = TSM.SRArea2 And TIA2.AttrTypeCode = 'AT00001' And TIA2.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_ITEM TI WITH(NOLOCK) ON TSM.SRArea3 = TI.ItemID Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA3 WITH(NOLOCK) ON TIA3.ItemID = TSM.SRArea3 And TIA3.AttrTypeCode = 'AT00001' And TIA3.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD2 WITH(NOLOCK) On TD2.TypeCode = TSM.ItemTypeCode And TD2.Category = 'OJ' And TD2.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD5 WITH(NOLOCK) On TD5.TypeCode = TSM.SRType And TD5.Category = 'SRTP' And TD5.LanguageID = #{languageID} Left Outer Join XBOLTAPP.ESM_SR_TYPE EST WITH(NOLOCK) On EST.srtypecode = TSM.srtype Left Outer Join XBOLTADM.TB_DICTIONARY TD6 WITH(NOLOCK) On TD6.TypeCode = EST.ItemTypeCode And TD6.Category = 'OJ' And TD6.LanguageID = #{languageID} Left Outer Join XBOLTAPP.CRM_CUST_MST CCM WITH(NOLOCK) ON TSM.ClientID = CCM.CustomerNo Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM6 WITH(NOLOCK) ON TEAM6.TeamID = CCM.TeamID And TEAM6.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_DICTIONARY TD8 WITH(NOLOCK) On TD8.TypeCode = TSM.ProcRoleTP And TD8.Category = 'SRROLETP' And TD8.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_TEAM TM WITH(NOLOCK) ON TM.TeamID = TSM.RequestTeamID Left Outer Join XBOLTAPP.CRM_CUST_MST CCM2 WITH(NOLOCK) ON CCM2.CustomerNo = TM.ClientID Left Outer Join XBOLTADM.TB_TEAM_TXT TMT WITH(NOLOCK) ON TMT.TeamID = CCM2.TeamID And TMT.LanguageID = #{languageID} ) AS TBD
AND TBD.ESType = #{esType}
AND TBD.SRType = #{srType}
AND #{sessionUserID} In (RequestUserID, ReceiptUserID , RegUserID)
AND #{sessionUserID} In ( ReceiptUserID )
AND #{sessionUserID} In ( ReceiptUserID, ResponseUserID )
AND #{sessionUserID} In (RequestUserID)
AND #{sessionUserID} In (RequestUserID, ReceiptUserID)
AND TBD.ClientID = (Select ClientID from XBOLTADM.TB_MEMBER Where MemberID = #{sessionUserID} )
AND TBD.SRID In (Select PID from XBOLTADM.TB_PROC_LOG where ActorID = #{sessionUserID} and ActivityID = 'ACTP003')
AND #{myTeamId} In (TBD.RequestTeamID, TBD.ReceiptTeamID)
AND #{sessionUserID} In (SELECT MemberID FROM XBOLTADM.TB_MY_ITEM WHERE ItemID = TBD.SRArea2 AND Assigned = '1')
And SvcCompl = 'N'
And SvcCompl = 'Y'
And TBD.IsPublic = 0
AND TBD.Status = #{srStatus}
AND TBD.Status IN (${srStatusArr})
AND TBD.ProjectID IN (Select ProjectID From XBOLTADM.TB_PROJECT Where RefPGID = #{refID} And ProjectType = 'PJT' )
AND TBD.ProjectID = #{refID}
AND TBD.ProjectID IN (Select ProjectID From XBOLTADM.TB_PJT_MEMBER_REL Where MemberID = #{sessionUserID} AND Involved = '1' )
AND ReqUserNM like N'%'+#{requestUserName}+'%'
AND RegUserName like N'%'+#{regUserName}+'%'
AND ReceiptName like N'%'+#{receiptUserName}+'%'
AND CONVERT(varchar(10), TBD.RegDate, 120) BETWEEN #{regStartDate} AND #{regEndDate}
AND TBD.SRArea1 = #{srArea1}
AND TBD.SRArea2 = #{srArea2}
AND TBD.Category = #{category}
AND TBD.SubCategory = #{subCategory}
AND TBD.Priority = #{priority}
AND CONVERT(varchar(10), TBD.SRdueDate, 120) BETWEEN #{stSRDueDate} AND #{endSRDueDate}
AND CONVERT(varchar(10), TBD.SRCompletionDT, 120) BETWEEN #{stSRCompDT} AND #{endSRCompDT}
AND Convert(varchar(10),TBD.CompletionDT, 120) <= #{completionDT}
AND TBD.SRCode like N'%'+#{srCode}+'%'
AND TBD.SrID = #{srID}
AND TBD.RequestTeamID = #{requestTeam}
AND TBD.ResponseTeamID = #{responseTeamID}
AND TBD.SRReceiptTeamID = #{srReceiptTeam}
AND TBD.ReceiptDelay = #{receiptDelay}
AND TBD.CompletionDelay = #{completionDelay}
AND TBD.Subject like N'%'+#{subject}+'%'
AND #{itemID} IN (TBD.SRArea1, TBD.SRArea2, TBD.SRArea3)
AND Classification = #{classification}
AND TBD.RequestTeamID IN (${requestTeamList})
AND ( TBD.CompanyID IN (${companyList}) OR TBD.RequestTeamID IN (${companyList}) )
AND TBD.CustGRNo = #{custGRNo}
AND TBD.ClientID = #{custNo})
AND TBD.ClientID = #{clientID}
AND TBD.CompanyID IN (#{companyID})
AND TBD.ItemCode like N'%'+#{itemCode}+'%'
AND TBD.ItemName like N'%'+#{itemName}+'%'
AND TBD.ItemTypeCode = #{itemTypeCode}
AND TBD.SRID in (Select ToSRID From XBOLTAPP.ESM_SR_CXN Where FromSRID = #{fromSRID})
AND (1=1
${item.selectOption} TBD.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR Where AttrTypeCode = #{item.attrCode} And ISNULL(Value,'') NOT Like replace('%'+#{item.searchValue}+'%', ' ','') )
${item.selectOption} TBD.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR Where AttrTypeCode = #{item.attrCode} And LovCode NOT IN (
#{item2}
) )
${item.selectOption} TBD.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR Where AttrTypeCode = #{item.attrCode} )
${item.selectOption} TBD.SRID NOT IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR Where AttrTypeCode = #{item.attrCode} )
)
And TBD.SRID IN (Select SRID From XBOLTAPP.ESM_MBR_RCD Where SRID = TBD.SRID And MemberID = #{sessionUserID} And WORK_DATE IS NULL)
And TBD.ProcRoleTP IN (Select RoleType From XBOLTADM.TB_MY_ITEM Where ItemID = TBD.SRArea2 AND Assigned = '1' And MemberID = #{sessionUserID})
And TBD.SRID IN ( Select PID From XBOLTAPP.ESM_ACTIVITY_LOG Where ActorID = #{sessionUserID} )
And TBD.ProjectID in ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP WITH(NOLOCK) left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR WITH(NOLOCK) on TP.ProjectID = TPMR.ProjectID Where TPMR.MemberID = #{sessionUserID} And TP.ProjectType = 'CSR' )
Order By TBD.RegDTOrg DESC

