INSERT INTO XBOLTDLM.COMTNFAQINFO
	   (FAQ_ID
	  , QESTN_SJ
	  , QESTN_CN
	  , ANSWER_CN
	  , RDCNT
	  , ATCH_FILE_ID
	  , FRST_REGIST_PNTTM 
	  , FRST_REGISTER_ID 
	  , LAST_UPDT_PNTTM 
	  , LAST_UPDUSR_ID
	  , ORGNZT_ID
	  , FAQ_TYPE
	  , URGNCY_YN) 
VALUES ( #{FaqID}
	  , #{Subject}
	  , #{Content}
	  , #{Answer}
	  , 0
	  , #{AtchFileId}
	  , GETDATE()
	  , #{sessionLoginId}
	  , GETDATE()
	  , #{sessionLoginId}
	  , #{ProjectID}
	  , #{Division}
	  , #{UrgncyYn})

mapper.update:
			UPDATE XBOLTDLM.COMTNFAQINFO SET
				  QESTN_SJ=#{Subject}
				  , QESTN_CN=#{Content}
				  , ANSWER_CN=#{Answer}
				  , ATCH_FILE_ID=#{AtchFileId}			  			
				  , LAST_UPDT_PNTTM=GETDATE()
				  , LAST_UPDUSR_ID=#{sessionLoginId}
				  , ORGNZT_ID=#{ProjectID}
				  , FAQ_TYPE=#{Division}
				  , URGNCY_YN=#{UrgncyYn}
 			WHERE  FAQ_ID=#{FaqID}

