Select B.LoginID AS STEP_MNG_ID, B.Name AS STEP_MNG_NM, Format(A.WORK_DATE,'yyyy-MM-dd') AS WORK_DATE, SUM(A.BUSINESS_HOURS + A.OVERTIME) AS WORK_TIME_MM From XBOLTAPP.VW_ESM_MBR_RCD A left outer join XBOLTADM.TB_MEMBER B ON B.MemberID = A.MemberID Where A.WORK_DATE BETWEEN #{startDate} and #{endDate} AND A.ClientID = #{customerNo}
And A.MemberID = #{receiptUserID}
AND A.ProjectID IN ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP WITH(NOLOCK) LEFT OUTER JOIN XBOLTADM.TB_PJT_MEMBER_REL TPMR WITH(NOLOCK) ON TP.ProjectID = TPMR.ProjectID WHERE TPMR.MemberID = #{userID} AND TP.ProjectType = 'CSR' ) GROUP BY B.LoginID, B.Name, A.WORK_DATE ORDER BY B.LoginID, B.Name, A.WORK_DATE

Select Row_Number()OVER(ORDER BY TBD.RegDTOrg DESC ) as RNUM, TBD.* INTO #temp_result From ( Select TSM.SRID TSM_SRID , TSM.RegDT RegDTOrg , TIS.ItemID TIS_ItemID , TISA.seq TISA_seq , TIA.Seq TIA_Seq , SRArea1ATR.seq SRArea1ATR_seq , SRArea２ATR.seq SRArea２ATR_seq From XBOLTAPP.ESM_SR_MST TSM WITH(NOLOCK) Left Outer Join XBOLTADM.TB_ITEM TIS WITH(NOLOCK) ON TSM.Status = TIS.Identifier Left Outer Join XBOLTADM.TB_ITEM_ATTR TISA WITH(NOLOCK) ON TISA.ItemID = TIS.ItemID And TISA.AttrTypeCode = 'AT00001' And TISA.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TIA.ItemID = TSM.SRArea1 And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA2 WITH(NOLOCK) ON TIA2.ItemID = TSM.SRArea2 And TIA2.AttrTypeCode = 'AT00001' And TIA2.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR SRArea1ATR WITH(NOLOCK) ON SRArea1ATR.ItemID = TSM.SRArea1 AND SRArea1ATR.AttrTypeCode = 'AT00035' AND SRArea1ATR.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR SRArea２ATR WITH(NOLOCK) ON SRArea２ATR.ItemID = TSM.SRArea1 AND SRArea２ATR.AttrTypeCode = 'AT00035' AND SRArea２ATR.LanguageID = #{languageID}
AND TSM.ESType = #{esType}
AND TSM.SRType = #{srType}
AND #{sessionUserID} In (TSM.RequestUserID, TSM.ReceiptUserID , TSM.RegUserID)
AND #{sessionUserID} In ( TSM.ReceiptUserID )
AND #{sessionUserID} In ( TSM.ResponseUserID ) AND ( TSM.ReceiptUserID IS NULL OR TSM.ReceiptUserID = #{sessionUserID})
AND #{sessionUserID} In (TSM.RequestUserID)
AND #{sessionUserID} In (TSM.RequestUserID, TSM.ReceiptUserID)
AND TSM.ClientID = (Select ClientID from XBOLTADM.TB_MEMBER Where MemberID = #{sessionUserID} )
AND TSM.SRID In (Select PID from XBOLTADM.TB_PROC_LOG where ActorID = #{sessionUserID} and ActivityID = 'ACTP003')
AND #{myTeamId} In (TSM.RequestTeamID, TSM.ReceiptTeamID)
AND #{sessionUserID} In (SELECT MemberID FROM XBOLTADM.TB_MY_ITEM WHERE ItemID = TSM.SRArea2 AND Assigned = '1')
AND TSM.Status = #{srStatus}
AND TSM.Status IN (${srStatusArr})
AND TSM.ProjectID IN (Select ProjectID From XBOLTADM.TB_PROJECT Where RefPGID = #{refID} And ProjectType = 'PJT' )
AND TSM.ProjectID = #{refID}
AND TSM.ProjectID IN (Select ProjectID From XBOLTADM.TB_PJT_MEMBER_REL Where MemberID = #{sessionUserID} AND Involved = '1' )
And TSM.ProjectID in ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR on TP.ProjectID = TPMR.ProjectID Where TPMR.MemberID = #{sessionUserID} And TP.ProjectType = 'CSR' )
AND TM3.Name like N'%'+#{requestUserName}+'%'
AND TM2.Name like N'%'+#{regUserName}+'%'
AND TM4.Name like N'%'+#{receiptUserName}+'%'
AND TSM.RegDT BETWEEN CAST(#{regStartDate} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{regEndDate} AS DATETIME)))
AND TSM.SRArea1 = #{srArea1}
AND TSM.SRArea2 = #{srArea2}
AND TSM.Category = #{category}
AND TSM.SubCategory = #{subCategory}
AND TSM.Priority = #{priority}
AND TSM.DueDate BETWEEN CAST(#{stSRDueDate} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{endSRDueDate} AS DATETIME)))
AND TSM.CompletionDT BETWEEN CAST(#{stSRCompDT} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{endSRCompDT} AS DATETIME)))
AND TSM.SRCode = #{srCode}
AND TSM.SrID = #{srID}
AND TSM.RequestTeamID = #{requestTeam}
AND TSM.ResponseTeamID = #{responseTeamID}
AND TSM.ReceiptTeamID = #{srReceiptTeam}
AND TSM.Subject like N'%'+#{subject}+'%'
AND #{itemID} IN (TSM.SRArea1, TSM.SRArea2, TSM.SRArea3)
AND TSM.RequestTeamID IN (${requestTeamList})
AND ( TSM.CompanyID IN (${companyList}) OR TSM.RequestTeamID IN (${companyList}) )
AND TSM.ClientID = #{clientID}
AND TSM.CompanyID IN (#{companyID})
AND TSM.isPublic = #{isPublic}
AND TSM.SRID in (Select ToSRID From XBOLTAPP.ESM_SR_CXN Where FromSRID = #{fromSRID})
AND (1=1
${item.selectOption} TSM.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR Where AttrTypeCode = #{item.attrCode} And ISNULL(Value,'') NOT Like replace('%'+#{item.searchValue}+'%', ' ','') )
${item.selectOption} TSM.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR Where AttrTypeCode = #{item.attrCode} And LovCode NOT IN (
#{item2}
) )
${item.selectOption} TSM.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR Where AttrTypeCode = #{item.attrCode} )
${item.selectOption} TSM.SRID NOT IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR Where AttrTypeCode = #{item.attrCode} )
)
And ( TSM.SRID IN (Select SRID From XBOLTAPP.ESM_MBR_RCD Where SRID = TSM.SRID And MemberID = #{sessionUserID} AND SpeCode = TSM.Status ) OR ( #{sessionUserID} In ( TSM.ReceiptUserID ) AND TSM.Blocked = 0 AND TSM.ProcRoleTP != 'CLIENT' AND TSM.ProcRoleTP IS NOT NULL ) )
And TSM.ProcRoleTP IN (Select RoleType From XBOLTADM.TB_MY_ITEM Where (ItemID = TSM.SRArea2 OR ItemID = TSM.SRArea1) AND Assigned = '1' And MemberID IN (${procRoleTPGroupMemberIDs}))
And TSM.SRID IN ( Select PID From XBOLTAPP.ESM_ACTIVITY_LOG Where ActorID = #{sessionUserID} )
AND TSM.RequestUserID = #{requestUserID}
And (TSM.SRID in ( SELECT distinct srid FROM XBOLTAPP.ESM_MBR_RCD Where MemberID = #{actorID}) or TSM.SRID IN (SELECT distinct DocumentID from XBOLTAPP.esm_activity_log where actorid = #{actorID}))
And TSM.CompletionDT iS NULL
And TSM.CompletionDT iS NOT NULL
And TSM.IsPublic = 0
AND ISNULL(SRArea2ATR.PlainText,SRArea1ATR.PlainText) = #{svcType}
AND TSM.Duedate < ISNULL(tsm.CompletionDT,GETDATE())
AND TSM.Duedate < ISNULL(tsm.CompletionDT,GETDATE())
) AS TBD
SELECT TXT.Name, count(TSM1.srID) 'ACM', count(TSM2.srID) 'DCM', count(TSM3.srID) 'ICM', count(TSM4.srID) 'SCM', count(TSM5.srID) 'DPL', count(TSM6.srID) 'WRK1', count(TSM7.srID) 'WRK2', count(TSM8.srID) 'REQ1', count(TSM9.srID) 'REQ2' From #temp_result tmp inner join xboltapp.esm_sr_mst TSM WITH(NOLOCK) ON TSM.SRID = tmp.TSM_SRID inner join xboltadm.tb_team TT WITH(NOLOCK) ON TT.ClientID = TSM.ClientID AND TT.TeamType = '2' inner join xboltadm.tb_team_txt TXT WITH(NOLOCK) ON TXT.TeamID = TT.TeamID AND TXT.LanguageID = #{languageID} left outer join xboltapp.esm_sr_mst TSM1 WITH(NOLOCK) ON TSM1.SRID = tmp.TSM_SRID AND TSM1.SRType = 'ACM' left outer join xboltapp.esm_sr_mst TSM2 WITH(NOLOCK) ON TSM2.SRID = tmp.TSM_SRID AND TSM2.SRType = 'DCM' left outer join xboltapp.esm_sr_mst TSM3 WITH(NOLOCK) ON TSM3.SRID = tmp.TSM_SRID AND TSM3.SRType = 'ICM' left outer join xboltapp.esm_sr_mst TSM4 WITH(NOLOCK) ON TSM4.SRID = tmp.TSM_SRID AND TSM4.SRType = 'SCM' left outer join xboltapp.esm_sr_mst TSM5 WITH(NOLOCK) ON TSM5.SRID = tmp.TSM_SRID AND TSM5.SRType = 'DPL' left outer join xboltapp.esm_sr_mst TSM6 WITH(NOLOCK) ON TSM6.SRID = tmp.TSM_SRID AND TSM6.SRType = 'WRK' AND TSM6.Status != 'WRK0003' left outer join xboltapp.esm_sr_mst TSM7 WITH(NOLOCK) ON TSM7.SRID = tmp.TSM_SRID AND TSM7.SRType = 'WRK' AND TSM7.Status = 'WRK0003' left outer join xboltapp.esm_sr_mst TSM8 WITH(NOLOCK) ON TSM8.SRID = tmp.TSM_SRID AND TSM8.SRType = 'REQ' AND TSM8.ProcPathID != '500039' left outer join xboltapp.esm_sr_mst TSM9 WITH(NOLOCK) ON TSM9.SRID = tmp.TSM_SRID AND TSM9.SRType = 'REQ' AND TSM9.ProcPathID = '500039' where TSM.srType != '' and TSM.srType is not null and TSM.ClientID != '' and TSM.ClientID is not null group by TSM.ClientID , TXT.Name order by TXT.Name
DROP TABLE #temp_result
